# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import websockets
import json
import uuid
from datetime import datetime
from typing import Dict, Set, Optional
from dataclasses import dataclass, asdict
from enum import Enum

class MessageType(Enum):
    LOGIN = "login"
    INVENTORY = "inventory"
    TRADE_REQUEST = "trade_request"
    TRADE_RESPONSE = "trade_response"
    TRADE_OFFER = "trade_offer"
    TRADE_ACCEPT = "trade_accept"
    TRADE_CANCEL = "trade_cancel"
    TRADE_CONFIRM = "trade_confirm"
    GIVE_ITEM = "give_item"
    ERROR = "error"
    SUCCESS = "success"

@dataclass
class Item:
    item_id: str
    name: str
    quantity: int
    description: str = ""

@dataclass
class TradeOffer:
    items: Dict[str, int]
    confirmed: bool = False

class Player:
    def __init__(self, player_id: str, name: str):
        self.player_id = player_id
        self.name = name
        self.inventory: Dict[str, Item] = {}
        self.websocket: Optional[websockets.WebSocketServerProtocol] = None
        self.current_trade: Optional[str] = None
        self.lock = asyncio.Lock()

    def add_item(self, item: Item):
        if item.item_id in self.inventory:
            self.inventory[item.item_id].quantity += item.quantity
        else:
            self.inventory[item.item_id] = item

    def remove_item(self, item_id: str, quantity: int) -> bool:
        if item_id not in self.inventory:
            return False
        if self.inventory[item_id].quantity < quantity:
            return False
        self.inventory[item_id].quantity -= quantity
        if self.inventory[item_id].quantity == 0:
            del self.inventory[item_id]
        return True

    def has_item(self, item_id: str, quantity: int) -> bool:
        return item_id in self.inventory and self.inventory[item_id].quantity >= quantity

    def get_inventory_dict(self):
        return {item_id: asdict(item) for item_id, item in self.inventory.items()}

class Trade:
    def __init__(self, trade_id: str, player1_id: str, player2_id: str):
        self.trade_id = trade_id
        self.player1_id = player1_id
        self.player2_id = player2_id
        self.player1_offer = TradeOffer(items={})
        self.player2_offer = TradeOffer(items={})
        self.lock = asyncio.Lock()
        self.active = True

    def get_offer(self, player_id: str) -> Optional[TradeOffer]:
        if player_id == self.player1_id:
            return self.player1_offer
        elif player_id == self.player2_id:
            return self.player2_offer
        return None

    def get_other_player_id(self, player_id: str) -> Optional[str]:
        if player_id == self.player1_id:
            return self.player2_id
        elif player_id == self.player2_id:
            return self.player1_id
        return None

class GameServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.active_trades: Dict[str, Trade] = {}
        self.websocket_to_player: Dict[websockets.WebSocketServerProtocol, str] = {}
        self.server_lock = asyncio.Lock()

    async def register_player(self, websocket, player_name: str) -> Player:
        player_id = str(uuid.uuid4())
        player = Player(player_id, player_name)
        player.websocket = websocket
        
        async with self.server_lock:
            self.players[player_id] = player
            self.websocket_to_player[websocket] = player_id
        
        player.add_item(Item(item_id="sword_001", name="Iron Sword", quantity=1, description="A basic iron sword"))
        player.add_item(Item(item_id="potion_001", name="Health Potion", quantity=5, description="Restores 50 HP"))
        player.add_item(Item(item_id="gold_001", name="Gold Coins", quantity=100, description="Currency"))
        
        return player

    async def unregister_player(self, websocket):
        async with self.server_lock:
            if websocket in self.websocket_to_player:
                player_id = self.websocket_to_player[websocket]
                if player_id in self.players:
                    player = self.players[player_id]
                    if player.current_trade:
                        await self.cancel_trade(player_id, player.current_trade)
                    del self.players[player_id]
                del self.websocket_to_player[websocket]

    async def send_message(self, websocket, message_type: str, data: dict):
        try:
            message = {
                "type": message_type,
                "timestamp": datetime.now().isoformat(),
                **data
            }
            await websocket.send(json.dumps(message))
        except:
            pass

    async def handle_login(self, websocket, data: dict):
        player_name = data.get("name", "Anonymous")
        player = await self.register_player(websocket, player_name)
        
        await self.send_message(websocket, MessageType.SUCCESS.value, {
            "message": "Login successful",
            "player_id": player.player_id,
            "player_name": player.name
        })
        
        await self.send_inventory(player)

    async def send_inventory(self, player: Player):
        if player.websocket:
            await self.send_message(player.websocket, MessageType.INVENTORY.value, {
                "inventory": player.get_inventory_dict()
            })

    async def handle_trade_request(self, player: Player, data: dict):
        target_player_id = data.get("target_player_id")
        
        if target_player_id not in self.players:
            await self.send_message(player.websocket, MessageType.ERROR.value, {
                "message": "Target player not found"
            })
            return

        if player.current_trade:
            await self.send_message(player.websocket, MessageType.ERROR.value, {
                "message": "You are already in a trade"
            })
            return

        target_player = self.players[target_player_id]
        
        if target_player.current_trade:
            await self.send_message(player.websocket, MessageType.ERROR.value, {
                "message": "Target player is already in a trade"
            })
            return

        if target_player.websocket:
            await self.send_message(target_player.websocket, MessageType.TRADE_REQUEST.value, {
                "from_player_id": player.player_id,
                "from_player_name": player.name
            })

    async def handle_trade_response(self, player: Player, data: dict):
        from_player_id = data.get("from_player_id")
        accept = data.get("accept", False)

        if from_player_id not in self.players:
            await self.send_message(player.websocket, MessageType.ERROR.value, {
                "message": "Requester not found"
            })
            return

        from_player = self.players[from_player_id]

        if not accept:
            if from_player.websocket:
                await self.send_message(from_player.websocket, MessageType.TRADE_CANCEL.value, {
                    "message": f"{player.name} declined the trade"
                })
            return

        trade_id = str(uuid.uuid4())
        trade = Trade(trade_id, from_player_id, player.player_id)
        
        async with self.server_lock:
            self.active_trades[trade_id] = trade
            from_player.current_trade = trade_id
            player.current_trade = trade_id

        if from_player.websocket:
            await self.send_message(from_player.websocket, MessageType.SUCCESS.value, {
                "message": f"Trade started with {player.name}",
                "trade_id": trade_id,
                "other_player": player.name
            })

        if player.websocket:
            await self.send_message(player.websocket, MessageType.SUCCESS.value, {
                "message": f"Trade started with {from_player.name}",
                "trade_id": trade_id,
                "other_player": from_player.name
            })

    async def handle_trade_offer(self, player: Player, data: dict):
        trade_id = data.get("trade_id")
        items_offered = data.get("items", {})

        if not player.current_trade or player.current_trade != trade_id:
            await self.send_message(player.websocket, MessageType.ERROR.value, {
                "message": "Invalid trade"
            })
            return

        if trade_id not in self.active_trades:
            await self.send_message(player.websocket, MessageType.ERROR.value, {
                "message": "Trade not found"
            })
            return

        trade = self.active_trades[trade_id]
        
        async with trade.lock:
            async with player.lock:
                for item_id, quantity in items_offered.items():
                    if not player.has_item(item_id, quantity):
                        await self.send_message(player.websocket, MessageType.ERROR.value, {
                            "message": f"Insufficient quantity of {item_id}"
                        })
                        return

                offer = trade.get_offer(player.player_id)
                offer.items = items_offered
                offer.confirmed = False

                other_offer = trade.get_offer(trade.get_other_player_id(player.player_id))
                other_offer.confirmed = False

            other_player_id = trade.get_other_player_id(player.player_id)
            if other_player_id and other_player_id in self.players:
                other_player = self.players[other_player_id]
                if other_player.websocket:
                    await self.send_message(other_player.websocket, MessageType.TRADE_OFFER.value, {
                        "trade_id": trade_id,
                        "from_player": player.name,
                        "items": items_offered
                    })

        await self.send_message(player.websocket, MessageType.SUCCESS.value, {
            "message": "Trade offer updated"
        })

    async def handle_trade_confirm(self, player: Player, data: dict):
        trade_id = data.get("trade_id")

        if not player.current_trade or player.current_trade != trade_id:
            await self.send_message(player.websocket, MessageType.ERROR.value, {
                "message": "Invalid trade"
            })
            return

        if trade_id not in self.active_trades:
            await self.send_message(player.websocket, MessageType.ERROR.value, {
                "message": "Trade not found"
            })
            return

        trade = self.active_trades[trade_id]
        
        async with trade.lock:
            offer = trade.get_offer(player.player_id)
            offer.confirmed = True

            other_player_id = trade.get_other_player_id(player.player_id)
            other_offer = trade.get_offer(other_player_id)

            if other_player_id in self.players:
                other_player = self.players[other_player_id]
                if other_player.websocket:
                    await self.send_message(other_player.websocket, MessageType.TRADE_CONFIRM.value, {
                        "trade_id": trade_id,
                        "player": player.name,
                        "confirmed": True
                    })

            if trade.player1_offer.confirmed and trade.player2_offer.confirmed:
                await self.execute_trade(trade_id)

    async def execute_trade(self, trade_id: str):
        if trade_id not in self.active_trades:
            return

        trade = self.active_trades[trade_id]
        
        if trade.player1_id not in self.players or trade.player2_id not in self.players:
            await self.cancel_trade(trade.player1_id, trade_id)
            return

        player1 = self.players[trade.player1_id]
        player2 = self.players[trade.player2_id]

        async with player1.lock:
            async with player2.lock:
                for item_id, quantity in trade.player1_offer.items.items():
                    if not player1.has_item(item_id, quantity):
                        await self.send_message(player1.websocket, MessageType.ERROR.value, {
                            "message": "Trade failed: Insufficient items"
                        })
                        await self.send_message(player2.websocket, MessageType.ERROR.value, {
                            "message": "Trade failed: Other player has insufficient items"
                        })
                        await self.cleanup_trade(trade_id)
                        return

                for item_id, quantity in trade.player2_offer.items.items():
                    if not player2.has_item(item_id, quantity):
                        await self.send_message(player1.websocket, MessageType.ERROR.value, {
                            "message": "Trade failed: Other player has insufficient items"
                        })
                        await self.send_message(player2.websocket, MessageType.ERROR.value, {
                            "message": "Trade failed: Insufficient items"
                        })
                        await self.cleanup_trade(trade_id)
                        return

                for item_id, quantity in trade.player1_offer.items.items():
                    item = player1.inventory[item_id]
                    player1.remove_item(item_id, quantity)
                    player2.add_item(Item(item_id=item.item_id, name=item.name, 
                                         quantity=quantity, description=item.description))

                for item_id, quantity in trade.player2_offer.items.items():
                    item = player2.inventory[item_id]
                    player2.remove_item(item_id, quantity)
                    player1.add_item(Item(item_id=item.item_id, name=item.name, 
                                         quantity=quantity, description=item.description))

        await self.send_message(player1.websocket, MessageType.SUCCESS.value, {
            "message": "Trade completed successfully"
        })
        await self.send_message(player2.websocket, MessageType.SUCCESS.value, {
            "message": "Trade completed successfully"
        })

        await self.send_inventory(player1)
        await self.send_inventory(player2)

        await self.cleanup_trade(trade_id)

    async def cancel_trade(self, player_id: str, trade_id: str):
        if trade_id not in self.active_trades:
            return

        trade = self.active_trades[trade_id]
        
        other_player_id = trade.get_other_player_id(player_id)
        
        if player_id in self.players:
            player = self.players[player_id]
            if player.websocket:
                await self.send_message(player.websocket, MessageType.TRADE_CANCEL.value, {
                    "message": "Trade cancelled"
                })

        if other_player_id and other_player_id in self.players:
            other_player = self.players[other_player_id]
            if other_player.websocket:
                await self.send_message(other_player.websocket, MessageType.TRADE_CANCEL.value, {
                    "message": "Trade cancelled by other player"
                })

        await self.cleanup_trade(trade_id)

    async def cleanup_trade(self, trade_id: str):
        if trade_id in self.active_trades:
            trade = self.active_trades[trade_id]
            
            if trade.player1_id in self.players:
                self.players[trade.player1_id].current_trade = None
            if trade.player2_id in self.players:
                self.players[trade.player2_id].current_trade = None
            
            async with self.server_lock:
                del self.active_trades[trade_id]

    async def handle_trade_cancel(self, player: Player, data: dict):
        trade_id = data.get("trade_id")
        
        if player.current_trade and player.current_trade == trade_id:
            await self.cancel_trade(player.player_id, trade_id)

    async def handle_give_item(self, player: Player, data: dict):
        target_player_id = data.get("target_player_id")
        item_id = data.get("item_id")
        quantity = data.get("quantity", 1)

        if target_player_id not in self.players:
            await self.send_message(player.websocket, MessageType.ERROR.value, {
                "message": "Target player not found"
            })
            return

        target_player = self.players[target_player_id]

        async with player.lock:
            async with target_player.lock:
                if not player.has_item(item_id, quantity):
                    await self.send_message(player.websocket, MessageType.ERROR.value, {
                        "message": "Insufficient items"
                    })
                    return

                item = player.inventory[item_id]
                player.remove_item(item_id, quantity)
                target_player.add_item(Item(item_id=item.item_id, name=item.name, 
                                           quantity=quantity, description=item.description))

        await self.send_message(player.websocket, MessageType.SUCCESS.value, {
            "message": f"Gave {quantity}x {item.name} to {target_player.name}"
        })

        if target_player.websocket:
            await self.send_message(target_player.websocket, MessageType.SUCCESS.value, {
                "message": f"Received {quantity}x {item.name} from {player.name}"
            })

        await self.send_inventory(player)
        await self.send_inventory(target_player)

    async def handle_client(self, websocket, path):
        player = None
        try:
            async for message in websocket:
                try:
                    data = json.loads(message)
                    msg_type = data.get("type")

                    if msg_type == MessageType.LOGIN.value:
                        await self.handle_login(websocket, data)
                        continue

                    if websocket not in self.websocket_to_player:
                        await self.send_message(websocket, MessageType.ERROR.value, {
                            "message": "Not logged in"
                        })
                        continue

                    player_id = self.websocket_to_player[websocket]
                    player = self.players.get(player_id)

                    if not player:
                        continue

                    if msg_type == MessageType.INVENTORY.value:
                        await self.send_inventory(player)
                    elif msg_type == MessageType.TRADE_REQUEST.value:
                        await self.handle_trade_request(player, data)
                    elif msg_type == MessageType.TRADE_RESPONSE.value:
                        await self.handle_trade_response(player, data)
                    elif msg_type == MessageType.TRADE_OFFER.value:
                        await self.handle_trade_offer(player, data)
                    elif msg_type == MessageType.TRADE_CONFIRM.value:
                        await self.handle_trade_confirm(player, data)
                    elif msg_type == MessageType.TRADE_CANCEL.value:
                        await self.handle_trade_cancel(player, data)
                    elif msg_type == MessageType.GIVE_ITEM.value:
                        await self.handle_give_item(player, data)

                except json.JSONDecodeError:
                    await self.send_message(websocket, MessageType.ERROR.value, {
                        "message": "Invalid JSON"
                    })
                except Exception as e:
                    await self.send_message(websocket, MessageType.ERROR.value, {
                        "message": f"Error: {str(e)}"
                    })

        finally:
            await self.unregister_player(websocket)

async def main():
    server = GameServer()
    async with websockets.serve(server.handle_client, "localhost", 8765):
        print("MMO Game Server running on ws://localhost:8765")
        await asyncio.Future()

if __name__ == "__main__":
    asyncio.run(main())